bu-split-editor.dark:
body.bu-split-editor .markdown-reading-view .markdown-preview-view {
background-image: var(--scrollable-background), var(--bu-grain);
background-size: 100% auto, auto;
background-repeat: repeat-y, repeat;
background-attachment: local, local;
}

body.bu-split-editor {
--bu-editor-bg: var(--bu-white-level, #e7e0cd);
--bu-editor-text: var(--bu-text-light, #1e1a14);
}

body.bu-split-editor .markdown-reading-view::after {
display: none;
}

body.bu-split-editor .markdown-rendered p, body.bu-split-editor .markdown-rendered li {
text-shadow: none;
}

bu-split-editor.light:
body.bu-split-editor {
--bu-editor-bg: var(--bu-black-level, #0c0b0a);
--bu-editor-text: var(--bu-text-dark, #f1efea);
}

body.bu-split-editor .markdown-reading-view .markdown-preview-view {
background-image: var(--scrollable-background);
background-size: 100% auto;
background-repeat: repeat-y;
background-attachment: local;
}

body.bu-split-editor .markdown-reading-view {
position: relative;
}

body.bu-split-editor .markdown-reading-view::after {
content: "";
position: absolute;
inset: 0;
pointer-events: none;
z-index: 4;
background: var(--bu-scanlines);
}

bu-glass-cards.general:
body.bu-glass-cards .metadata-container {
background-color: color-mix(in srgb, var(--bu-raised) 70%, transparent);
border: 1px solid color-mix(in srgb, var(--bu-text-hi) 9%, transparent);
box-shadow: var(--bu-glass-tl), var(--bu-glass-br), 0 8px 24px -6px var(--bu-shadow);
}

body.bu-glass-cards .metadata-property-value {
background-color: color-mix(in srgb, var(--bu-bg) 55%, transparent);
border-radius: 6px;
box-shadow: inset 0 1px 3px var(--bu-shadow-soft);
padding: 2px 4px 2px 10px;
}

body.bu-glass-cards .metadata-property:hover .metadata-property-value {
background-color: color-mix(in srgb, var(--bu-bg) 70%, transparent);
}

bu-fullscreen-crt.general:
body.is-fullscreen.bu-fullscreen-crt .markdown-reading-view {
position: relative;
}

body.is-fullscreen.bu-fullscreen-crt .status-bar {
opacity: 0.2;
transition: opacity 0.3s ease;
}

body.is-fullscreen.bu-fullscreen-crt .status-bar:hover {
opacity: 1;
}

bu-fullscreen-crt.dark:
body.is-fullscreen.bu-fullscreen-crt .markdown-reading-view::before {
content: "";
position: absolute;
inset: 0;
pointer-events: none;
z-index: 3;
background: radial-gradient(130% 110% at 50% 50%, transparent 32%, rgba(0, 0, 0, 0.5) 68%, rgba(0, 0, 0, 0.95) 100%);
}

body.is-fullscreen.bu-fullscreen-crt .markdown-reading-view::after {
background: repeating-linear-gradient(to bottom,
    transparent 0,
    transparent calc(var(--bu-scanline-period, 3) * 1px - 1px),
    rgba(0, 0, 0, 0.5) calc(var(--bu-scanline-period, 3) * 1px - 1px),
    rgba(0, 0, 0, 0.5) calc(var(--bu-scanline-period, 3) * 1px));
}

body.is-fullscreen.bu-fullscreen-crt .markdown-rendered p, body.is-fullscreen.bu-fullscreen-crt .markdown-rendered li {
text-shadow: 0 0 calc(var(--bu-glow-text, 55) * 0.13px) color-mix(in srgb, var(--bu-accent) calc(var(--bu-glow-text, 55) * 1.4%), transparent);
}

bu-anim.general:
button, .nav-file-title, .nav-folder-title, .tree-item-self, a.internal-link, a.external-link, .nn-navitem, .nn-file, .suggestion-item, .status-bar-item, .checkbox-container, .menu-item, .view-action) {
transition:
    background-color var(--bu-t-fast) var(--bu-anim-ease),
    color            var(--bu-t-fast) var(--bu-anim-ease),
    border-color     var(--bu-t-fast) var(--bu-anim-ease),
    opacity          var(--bu-t-fast) var(--bu-anim-ease),
    transform        var(--bu-t-fast) var(--bu-anim-ease),
    box-shadow       var(--bu-t-fast) var(--bu-anim-ease);
}

body.bu-anim :is(.nav-file-title, .nav-folder-title, .tree-item-self.is-clickable, .nn-navitem, .nn-file) {
transition: transform 190ms var(--bu-rolodex-ease), box-shadow 190ms var(--bu-rolodex-ease);
}

body.bu-anim :is(.nav-file-title, .nav-folder-title, .tree-item-self.is-clickable, .nn-navitem, .nn-file):hover {
transform: scale(1.05);
position: relative;
z-index: 3;
box-shadow: 0 5px 14px -5px var(--bu-shadow);
}

body.bu-anim :is(.nn-navitem, .nn-file).nn-selected, body.bu-anim .tree-item-self.is-active {
transform: scale(1.07);
position: relative;
z-index: 4;
filter: drop-shadow(0 4px 9px var(--bu-shadow));
}

.markdown-preview-view) {
animation: bu-poweron var(--bu-t-slow) var(--bu-anim-ease);
