}

bu-scrollbar-fade.general:
body.bu-scrollbar-fade ::-webkit-scrollbar-thumb {
background-color: transparent;
/* Leaving the scroll area: hold the thumb for the fade delay, then ease it out. */
transition: background-color var(--bu-t-slow) ease var(--bu-scrollbar-fade-delay, 1500ms);
}

body.bu-scrollbar-fade *:hover::-webkit-scrollbar-thumb {
background-color: var(--scrollbar-thumb-bg);
transition-delay: 0s;
/* entering: show at once, no delay */
}

bu-scrollbar-accent.general:
body.bu-scrollbar-accent ::-webkit-scrollbar-thumb {
transition: background-color var(--bu-t-slow) ease;
}

body.bu-scrollbar-accent ::-webkit-scrollbar-thumb:hover, body.bu-scrollbar-accent ::-webkit-scrollbar-thumb:active {
